// $json.output looks like ```json { "sql": "...", "explain": "..." } ```
const raw = ($json.output || '')
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

const parsed = JSON.parse(raw);

const statements = (parsed.sql || '')
  .split(';')
  .map(s => s.trim())
  .filter(Boolean)
  .map(s => s + ';');

return statements.map(sql => ({
  json: { sql, explain: parsed.explain }
}));
